const XLSX = require('xlsx');
const wb = XLSX.readFile('sales.xlsx');
XLSX.writeFile(wb, 'sales_backup.xlsx');

Workbook wb = WorkbookFactory.create(new File("sales.xlsx"));
FileOutputStream out = new FileOutputStream("sales_backup.xlsx");
wb.write(out);
wb.close();

-- Export workbook data
SELECT * INTO sales_backup FROM sales;
SELECT * INTO customers_backup FROM customers;
